package keeper

import (
	"context"
	sdk "github.com/cosmos/cosmos-sdk/types"
	"cosmossdk.io/collections"
	"github.com/example/project/x/counter/types"
)

type Keeper struct {
	Schema collections.Schema
	Counters *collections.Map[collections.Bytes, uint64]
}

func NewKeeper(schema collections.Schema) Keeper {
	counters := collections.NewMap[sdk.AccAddress, uint64](schema, types.StoreKey, "counters")
	return Keeper{
		Schema: schema,
		Counters: counters,
	}
}

func (k Keeper) GetCounter(ctx sdk.Context, addr sdk.AccAddress) (uint64, error) {
	count, err := k.Counters.Get(ctx.KVStore(k.Schema), addr)
	if err != nil && !collections.IsNotFound(err) {
		return 0, err
	}
	return count, nil
}

func (k Keeper) SetCounter(ctx sdk.Context, addr sdk.AccAddress, value uint64) error {
	store := ctx.KVStore(k.Schema)
	return k.Counters.Set(store, addr, value)
}

func (k Keeper) IncrementCounter(ctx sdk.Context, addr sdk.AccAddress) error {
	count, err := k.GetCounter(ctx, addr)
	if err != nil && !collections.IsNotFound(err) {
		return err
	}
	count++
	return k.SetCounter(ctx, addr, count)
}

func (k Keeper) ResetCounter(ctx sdk.Context, addr sdk.AccAddress) error {
	store := ctx.KVStore(k.Schema)
	return k.Counters.Remove(store, addr)
}
```

