package types

import (
	sdk "github.com/cosmos/cosmos-sdk/types"
)

type GenesisState struct {
	Counters map[string]uint64 `json:"counters"`
}

func NewGenesisState(counters map[string]uint64) *GenesisState {
	return &GenesisState{
		Counters: counters,
	}
}

func DefaultGenesisState() *GenesisState {
	return &GenesisState{
		Counters: make(map[string]uint64),
	}
}

func (gs GenesisState) ValidateBasic() error {
	for addrStr := range gs.Counters {
		if _, err := sdk.AccAddressFromBech32(addrStr); err != nil {
			return sdkerrors.Wrapf(sdkerrors.ErrInvalidAddress, "invalid address (%s)", addrStr)
		}
	}
	return nil
}

func (gs GenesisState) ExportGenesis(ctx sdk.Context, k keeper.Keeper) *GenesisState {
	counters := make(map[string]uint64)
	k.Counters.Walk(ctx.KVStore(k.Schema), func(key []byte, value uint64) error {
		addrStr := sdk.AccAddress(key).String()
		counters[addrStr] = value
		return nil
	})
	return &GenesisState{
		Counters: counters,
	}
}

func InitGenesis(ctx sdk.Context, k keeper.Keeper, gs GenesisState) []sdk.Event {
	for addrStr, count := range gs.Counters {
		addr, _ := sdk.AccAddressFromBech32(addrStr)
		k.SetCounter(ctx, addr, count)
	}
	return nil
}
