package main

import (
	"crypto/ed25519"
	"crypto/rand"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io/ioutil"
	"net/http"

	"golang.org/x/crypto/pem"
)

// KeyPair holds the private and public keys.
type KeyPair struct {
	privateKey ed25519.PrivateKey
	publicKey  ed25519.PublicKey
}

// MessageRequest is the expected JSON structure for POST requests.
type MessageRequest struct {
	Message string `json:"message"`
}

// SignatureResponse is the JSON response structure.
type SignatureResponse struct {
	Signature string `json:"signature"`
	Pubkey    string `json:"pubkey"`
}

// LoadPrivateKey loads an Ed25519 private key from a PEM file.
func LoadPrivateKey(pemFilePath string) (ed25519.PrivateKey, error) {
	pemData, err := ioutil.ReadFile(pemFilePath)
	if err != nil {
		return nil, err
	}

	block, _ := pem.Decode([]byte(pemData))
	if block == nil || block.Type != "PRIVATE KEY" {
		return nil, errors.New("failed to decode PEM block containing the private key")
	}

	privateKey, err := ed25519.ParsePrivateKey(block.Bytes)
	if err != nil {
		return nil, err
	}

	return privateKey, nil
}

// GeneratePublicKey generates the public key from a given private key.
func GeneratePublicKey(privateKey ed25519.PrivateKey) ed25519.PublicKey {
	publicKey := privateKey.Public().(ed25519.PublicKey)
	return publicKey
}

// SignMessage signs a message with the provided Ed25519 private key.
func SignMessage(privateKey ed25519.PrivateKey, message []byte) ([]byte, error) {
	signature := ed25519.Sign(privateKey, message)
	return signature, nil
}

// ValidateRequest validates the request body.
func ValidateRequest(req *http.Request) (*MessageRequest, error) {
	if req.ContentLength == 0 || req.ContentLength > 1024*1024 { // Max size: 1MB
		return nil, errors.New("request body is empty or too large")
	}

	var msg MessageRequest
	err := json.NewDecoder(req.Body).Decode(&msg)
	if err != nil {
		return nil, fmt.Errorf("invalid JSON format: %v", err)
	}

	if msg.Message == "" {
		return nil, errors.New("message cannot be empty")
	}

	return &msg, nil
}

// SignHandler handles POST requests to sign messages.
func (kp *KeyPair) SignHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	msgReq, err := ValidateRequest(r)
	if err != nil {
		http.Error(w, fmt.Sprintf("Bad request: %v", err), http.StatusBadRequest)
		return
	}

	signature, err := SignMessage(kp.privateKey, []byte(msgReq.Message))
	if err != nil {
		http.Error(w, "Failed to sign message", http.StatusInternalServerError)
		return
	}

	sigHex := hex.EncodeToString(signature)
	pubkeyHex := hex.EncodeToString(kp.publicKey)

	resp := SignatureResponse{
		Signature: sigHex,
		Pubkey:    pubkeyHex,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

func main() {
	privateKey, err := LoadPrivateKey("private_key.pem")
	if err != nil {
		fmt.Printf("Failed to load private key: %v\n", err)
		return
	}

	publicKey := GeneratePublicKey(privateKey)

	keyPair := &KeyPair{
		privateKey: privateKey,
		publicKey:  publicKey,
	}

	http.HandleFunc("/sign", keyPair.SignHandler)

	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}
