            if filter_pattern is None or filter_pattern in msg['message']:
                filtered_messages.append(msg)

    if json_output:
        print(json.dumps({"action": "check", "messages": filtered_messages}))
    else:
        if not filtered_messages:
            print_colored("No messages found.", ANSI_YELLOW)
        for msg in filtered_messages:
            print(f"Channel: {msg['id']} - Message: {msg['message']}")

def history(channel, limit=None, json_output=False):
    if channel not in messages:
        print_colored(f"Channel '{channel}' does not exist.", ANSI_RED)
        return

    msgs = messages[channel]
    if limit is not None:
        msgs = msgs[-limit:]

    if json_output:
        print(json.dumps({"action": "history", "channel": channel, "messages": msgs}))
    else:
        if not msgs:
            print_colored(f"No history found for channel '{channel}'.", ANSI_YELLOW)
        for msg in msgs:
            print(f"ID: {msg['id']} - Message: {msg['message']}")

def main():
    parser = argparse.ArgumentParser(description="CLI tool for managing messages.")
    subparsers = parser.add_subparsers(dest='command', required=True)

    # Send command
    send_parser = subparsers.add_parser('send', help='Send a message to a channel')
    send_parser.add_argument('channel', type=str, help='The channel to send the message to')
    send_parser.add_argument('message', type=str, help='The message to send')
    send_parser.add_argument('--json', action='store_true', help='Output in JSON format')

    # Check command
    check_parser = subparsers.add_parser('check', help='Check messages with optional filter')
    check_parser.add_argument('--filter', type=str, help='Filter messages by pattern')
    check_parser.add_argument('--json', action='store_true', help='Output in JSON format')

    # History command
    history_parser = subparsers.add_parser('history', help='Show message history for a channel')
    history_parser.add_argument('channel', type=str, help='The channel to show history for')
    history_parser.add_argument('--limit', type=int, help='Limit the number of messages shown')
    history_parser.add_argument('--json', action='store_true', help='Output in JSON format')

    args = parser.parse_args()

    try:
        if args.command == 'send':
            send_message(args.channel, args.message, args.json)
        elif args.command == 'check':
            check_messages(args.filter, args.json)
        elif args.command == 'history':
            history(args.channel, args.limit, args.json)
    except Exception as e:
        print_colored(f"Error: {e}", ANSI_RED)

if __name__ == '__main__':
    main()
